const queueItems = $items('Read QUEUE');
const controlRows = $items('Read CONTROL').map(i => i.json);
const publishedRows = $items('Read PUBLISHED List').map(i => i.json);

const control = Object.fromEntries(controlRows.map(r => [String(r.setting_key || '').trim(), r.setting_value]));

const toBool = (v, def = false) => {
  if (v === undefined || v === null || v === '') return def;
  if (typeof v === 'boolean') return v;
  return String(v).toLowerCase() === 'true';
};

const blank = (v) => v === undefined || v === null || String(v).trim() === '';

const maxPosts = Number(control.max_posts_per_day || 2);
const queuePickStatus = String(control.queue_pick_status || 'queued').toLowerCase();
const defaultLanguage = String(control.default_language || 'en');
const defaultGeo = String(control.default_geo_scope || 'Korea');
const wpStatus = String(control.wordpress_post_status || 'draft');
const autoFaq = toBool(control.auto_faq_enabled, true);
const autoShortform = toBool(control.auto_shortform_enabled, true);
const adsenseSafe = toBool(control.adsense_safe_mode, true);
const timezone = String(control.timezone || 'Asia/Seoul');
const today = new Date().toISOString().slice(0, 10);
const compact = today.replace(/-/g, '');
const now = new Date();

// Build comprehensive published articles list for internal linking
const publishedArticles = publishedRows
  .filter(p => !blank(p.published_url) && !blank(p.title))
  .map(p => ({
    title: p.title,
    url: p.published_url,
    category: p.category || '',
    subcategory: p.subcategory || '',
    keyword: p.primary_keyword || '',
    wp_post_id: p.wp_post_id || '',
    slug: p.slug || '',
    title_keywords: (p.title || '').toLowerCase().replace(/[^a-z0-9\s]/g, '').split(/\s+/).filter(w => w.length > 3)
  }));

const candidatesWithIndex = queueItems
  .map((item, idx) => ({ row: item.json, originalIndex: idx }))
  .filter(({ row: r }) => {
    const status = String(r.status || '').toLowerCase();
    const retryCount = Number(r.retry_count || 0);
    const nextRetryAt = String(r.next_retry_at || '').trim();
    const retryOk = nextRetryAt === '' || new Date(nextRetryAt) <= now;

    return status === queuePickStatus
      && retryCount < 3
      && retryOk
      && !blank(r.seed_keyword)
      && !blank(r.problem_angle)
      && !blank(r.category)
      && !blank(r.subcategory)
      && !blank(r.target_type)
      && !blank(r.content_type)
      && !blank(r.language || defaultLanguage)
      && blank(r.published_url);
  })
  .sort((a, b) => a.originalIndex - b.originalIndex)
  .slice(0, maxPosts);

return candidatesWithIndex.map(({ row, originalIndex }, idx) => {
  const topicId = !blank(row.topic_id)
    ? row.topic_id
    : `KRY-${compact}-${String(idx + 1).padStart(3, '0')}`;

  const rowNumber = originalIndex + 2;

  const currentCategory = row.category || '';
  const currentSubcategory = row.subcategory || '';
  const currentKeywords = (row.seed_keyword || '').toLowerCase().split(/\s+/).filter(w => w.length > 2);

  const relatedArticles = publishedArticles
    .map(article => {
      let score = 0;
      if (article.category.toLowerCase() === currentCategory.toLowerCase()) score += 3;
      if (article.subcategory.toLowerCase() === currentSubcategory.toLowerCase()) score += 5;
      const overlap = currentKeywords.filter(k => 
        article.title_keywords.includes(k) || 
        article.keyword.toLowerCase().includes(k)
      ).length;
      score += overlap * 2;
      return { ...article, relevance_score: score };
    })
    .filter(a => a.relevance_score >= 3)
    .sort((a, b) => b.relevance_score - a.relevance_score)
    .slice(0, 5)
    .map(a => ({ title: a.title, url: a.url, category: a.category }));

  return {
    json: {
      ...row,
      row_number: rowNumber,
      topic_id: topicId,
      language: row.language || defaultLanguage,
      geo_scope: row.geo_scope || defaultGeo,
      wordpress_post_status: wpStatus,
      auto_faq_enabled: autoFaq,
      auto_shortform_enabled: autoShortform,
      adsense_safe_mode: adsenseSafe,
      timezone,
      created_at_runtime: today,
      related_articles: relatedArticles,
      all_published_articles: publishedArticles
    }
  };
});

const itemIndex = $itemIndex;
const row = $items('Prepare Candidates')[itemIndex]?.json || {};

if (!row.seed_keyword) {
  throw new Error(`Build Draft Prompt: seed_keyword is missing.`);
}

const systemPrompt = `You are a senior editorial strategist and SEO writer for Koreayo, a practical English-language content site for foreigners living in Korea.

You must follow these rules strictly:
1. Write for real users, not for search engines.
2. The target reader is a foreigner in Korea or preparing to come to Korea.
3. Give the answer early. The first paragraph must contain a direct, practical answer.
4. Do not write fluffy introductions or vague motivational language.
5. Do not invent legal, visa, tax, banking facts.
6. Keep the tone practical, clear, calm, and trustworthy.
7. Use simple English.
8. Output valid JSON only.

=== TITLE RULES ===
- No special characters except comma and question mark.

=== CONTENT STYLE ===
- Write in PROSE style with full paragraphs.
- Each section MUST have 2-3 sentences before any bullet points.
- Aim for 70% prose, 30% bullets.

=== INTERNAL LINKING ===
- Add 2-4 internal links to related articles.
- Use EXACT URLs provided.
- Place links naturally within sentences.
- DO NOT add links in first paragraph or headings.

=== CONTENT LENGTH ===
- Minimum 1,200 words.
- Each H2 section: 150-200 words minimum.

Output JSON schema:
{
  "title": "string",
  "slug": "string",
  "meta_description": "string",
  "excerpt": "string",
  "primary_keyword": "string",
  "secondary_keywords": ["string"],
  "body_markdown": "string",
  "faq": [{"question": "string", "answer": "string"}],
  "internal_links_used": [{"anchor_text": "string", "url": "string"}]
}`;

const relatedArticlesInfo = (row.related_articles || [])
  .map(a => `- "${a.title}" - URL: ${a.url}`)
  .join('\n');

const userPrompt = `Create one article draft for Koreayo.

Topic:
- category: ${row.category}
- subcategory: ${row.subcategory}
- seed_keyword: ${row.seed_keyword}
- problem_angle: ${row.problem_angle}
- content_type: ${row.content_type}
- search_intent: ${row.search_intent}
- language: ${row.language}

=== RELATED ARTICLES FOR INTERNAL LINKING ===
${relatedArticlesInfo || 'No related articles yet.'}

Include 2-4 internal links naturally. Output valid JSON only.`;

return [{ json: { ...row, draft_system_prompt: systemPrompt, draft_user_prompt: userPrompt } }];

const sourceItems = $items('Prepare Candidates');
const inputItems = $input.all();

function extractJson(text) {
  const cleaned = String(text || '').replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```$/i, '').trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  if (first === -1 || last === -1) throw new Error('No JSON found');
  return JSON.parse(cleaned.slice(first, last + 1));
}

return inputItems.map((item, idx) => {
  const src = sourceItems[idx]?.json || {};
  const text = item.json?.choices?.[0]?.message?.content || '';
  const draft = extractJson(text);
  return { json: { ...src, draft_raw: text, draft_json: draft } };
});

const row = $json;

const systemPrompt = `You are a QA editor for Koreayo. Review drafts and output publish-ready articles.

Scoring (0-100 scale):
- content_depth: 1,200+ words = 75+
- internal_linking: 2-4 natural links = 75+

If internal_linking < 75, ADD links using related_articles.

Output JSON:
{
  "decision": "approve | revise | reject",
  "overall_score": 0-100,
  "scores": { "content_depth": 0-100, "internal_linking": 0-100 },
  "final_title": "string",
  "final_slug": "string",
  "final_meta_description": "string",
  "final_excerpt": "string",
  "final_body_markdown": "string",
  "final_faq": [{"question": "string", "answer": "string"}],
  "internal_links_added": [{"anchor_text": "string", "url": "string"}]
}`;

const relatedArticlesInfo = (row.related_articles || []).map(a => `- "${a.title}" - URL: ${a.url}`).join('\n');

const userPrompt = `Review this draft.

Topic: ${row.seed_keyword}
Category: ${row.category} > ${row.subcategory}

Related articles for linking:\n${relatedArticlesInfo || 'None'}

Draft:\n${JSON.stringify(row.draft_json, null, 2)}

Ensure 2-4 internal links. Output valid JSON.`;

return [{ json: { ...row, qa_system_prompt: systemPrompt, qa_user_prompt: userPrompt } }];

const sourceItems = $items('Parse Draft JSON');
const inputItems = $input.all();

function extractJson(text) {
  const cleaned = String(text || '').replace(/^```json\s*/i, '').replace(/```$/i, '').trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  if (first === -1 || last === -1) throw new Error('No JSON found');
  return JSON.parse(cleaned.slice(first, last + 1));
}

function markdownToHtml(md, faq, related) {
  if (!md) return '';
  let html = md;

  // H1 제목 제거 (본문에 제목이 중복되지 않도록)
  html = html.replace(/^#\s+.+$/gm, '');

  // 링크 변환
  html = html.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2" style="color:#2563eb;text-decoration:underline;">$1</a>');

  // 헤딩 변환 (H2, H3, H4)
  html = html.replace(/^####\s+(.+)$/gm, '<h4>$1</h4>');
  html = html.replace(/^###\s+(.+)$/gm, '<h3>$1</h3>');
  html = html.replace(/^##\s+(.+)$/gm, '<h2>$1</h2>');

  // 볼드 변환
  html = html.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');

  // 불릿 리스트 및 숫자 리스트 변환
  const lines = html.split('\n');
  let result = [];
  let inList = false;
  let listType = null;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const bulletMatch = line.match(/^[-*]\s+(.+)$/);
    const numberMatch = line.match(/^\d+\.\s+(.+)$/);

    if (bulletMatch) {
      if (!inList || listType !== 'ul') {
        if (inList) result.push(listType === 'ul' ? '</ul>' : '</ol>');
        result.push('<ul>');
        inList = true;
        listType = 'ul';
      }
      result.push('<li>' + bulletMatch[1] + '</li>');
    } else if (numberMatch) {
      if (!inList || listType !== 'ol') {
        if (inList) result.push(listType === 'ul' ? '</ul>' : '</ol>');
        result.push('<ol>');
        inList = true;
        listType = 'ol';
      }
      result.push('<li>' + numberMatch[1] + '</li>');
    } else {
      if (inList) {
        result.push(listType === 'ul' ? '</ul>' : '</ol>');
        inList = false;
        listType = null;
      }
      if (line.trim() && !line.startsWith('<h') && !line.startsWith('<ul') && !line.startsWith('<ol') && !line.startsWith('<li') && !line.startsWith('</')) {
        result.push('<p>' + line + '</p>');
      } else if (line.trim()) {
        result.push(line);
      }
    }
  }
  if (inList) {
    result.push(listType === 'ul' ? '</ul>' : '</ol>');
  }

  html = result.join('\n');

  let faqHtml = '';
  if (faq && faq.length > 0) {
    faqHtml = '<div style="margin-top:2rem;"><h2>FAQ</h2>' + faq.map(f => `<p><strong>Q: ${f.question}</strong></p><p>A: ${f.answer}</p>`).join('') + '</div>';
  }

  let relatedHtml = '';
  if (related && related.length > 0) {
    relatedHtml = '<div style="margin-top:2rem;"><h2>You Might Also Like</h2>' + related.map(r => `<p><a href="${r.url}">${r.title}</a></p>`).join('') + '</div>';
  }

  return html + faqHtml + relatedHtml;
}

return inputItems.map((item, idx) => {
  const src = sourceItems[idx]?.json || {};
  // Claude API returns content in item.json.content[0].text format
  const text = item.json?.content?.[0]?.text || item.json?.choices?.[0]?.message?.content || '';
  const qa = extractJson(text);
  const rawScore = Number(qa.overall_score || 0);
  const score = rawScore <= 10 ? rawScore * 10 : rawScore;
  const decision = String(qa.decision || '').toLowerCase().trim();
  const shouldSave = (decision === 'approve') || (decision === 'revise' && score >= 60);
  const related = (src.related_articles || []).slice(0, 3);
  const bodyHtml = markdownToHtml(qa.final_body_markdown || '', qa.final_faq || [], related);
  let cleanTitle = (qa.final_title || '').replace(/[:*#|\[\]"'\-]/g, '').trim();

  return {
    json: {
      ...src,
      qa_json: qa,
      should_save: shouldSave,
      final_title: cleanTitle,
      final_slug: qa.final_slug,
      final_meta_description: qa.final_meta_description,
      final_excerpt: qa.final_excerpt,
      final_body_html: bodyHtml,
      final_faq: qa.final_faq,
      internal_links_added: qa.internal_links_added || [],
      qa_decision: qa.decision,
      qa_score: qa.overall_score
    }
  };
});

const wpResponse = $json;
const originalData = $items('IF Should Save')[$itemIndex]?.json || {};
return { json: { ...originalData, wp_id: wpResponse.id, wp_link: wpResponse.link, wp_guid: wpResponse.guid?.rendered || '', wp_status: wpResponse.status, wp_slug: wpResponse.slug } };

const rowNumber = $json.row_number;
if (!rowNumber) throw new Error('row_number missing');
return { row_number: rowNumber, topic_id: $json.topic_id || '', status: 'published', retry_count: Number($json.retry_count || 0), qa_score: Number($json.qa_score || 0), qa_decision: $json.qa_decision || 'approve', published_url: $json.wp_link || '', last_error: '', next_retry_at: '', note: `${$json.note || ''} | published` };

const rowNumber = $json.row_number;
if (!rowNumber) throw new Error('row_number missing');
const retryCount = Number($json.retry_count || 0) + 1;
const nextStatus = retryCount >= 3 ? 'blocked' : 'queued';
return { row_number: rowNumber, topic_id: $json.topic_id || '', status: nextStatus, retry_count: retryCount, qa_score: Number($json.qa_score || 0), qa_decision: $json.qa_decision || 'reject', last_error: `QA failed: ${$json.qa_decision}`, next_retry_at: nextStatus === 'queued' ? new Date().toISOString() : '', note: `${$json.note || ''} | auto-fail`, seed_keyword: $json.seed_keyword || '', category: $json.category || '', subcategory: $json.subcategory || '' };

