// Prepare bidirectional linking: find related existing posts to update
// Get data from Merge WP Result node which has all the original data
const mergeData = $items('Merge WP Result')[0]?.json || {};

const newPost = {
  wp_post_id: mergeData.wp_id,
  title: mergeData.final_title,
  url: mergeData.wp_link,
  category: mergeData.category,
  subcategory: mergeData.subcategory,
  primary_keyword: mergeData.seed_keyword,
  slug: mergeData.final_slug || mergeData.wp_slug
};

const allPublished = mergeData.all_published_articles || [];

if (!newPost.wp_post_id || !newPost.url || allPublished.length < 2) {
  return [{ json: { skip: true, reason: 'Not enough data for bidirectional linking', new_post: newPost } }];
}

const newPostKeywords = (newPost.title || '').toLowerCase().replace(/[^a-z0-9\s]/g, '').split(/\s+/).filter(w => w.length > 3);

const relatedPosts = allPublished
  .filter(post => post.wp_post_id && String(post.wp_post_id) !== String(newPost.wp_post_id) && post.url)
  .map(post => {
    let score = 0;
    if (post.category && newPost.category && post.category.toLowerCase() === newPost.category.toLowerCase()) score += 3;
    if (post.subcategory && newPost.subcategory && post.subcategory.toLowerCase() === newPost.subcategory.toLowerCase()) score += 5;
    const postKeywords = (post.title || '').toLowerCase().replace(/[^a-z0-9\s]/g, '').split(/\s+/).filter(w => w.length > 3);
    const overlap = newPostKeywords.filter(k => postKeywords.includes(k)).length;
    score += overlap * 2;
    if (post.keyword && newPost.primary_keyword) {
      if (post.keyword.toLowerCase().includes(newPost.primary_keyword.toLowerCase()) || newPost.primary_keyword.toLowerCase().includes(post.keyword.toLowerCase())) score += 4;
    }
    return { ...post, relevance_score: score };
  })
  .filter(post => post.relevance_score >= 4)
  .sort((a, b) => b.relevance_score - a.relevance_score)
  .slice(0, 3);

if (relatedPosts.length === 0) {
  return [{ json: { skip: true, reason: 'No related posts found', new_post: newPost } }];
}

return relatedPosts.map(post => ({
  json: {
    target_wp_post_id: post.wp_post_id,
    target_title: post.title,
    target_url: post.url,
    new_post: newPost,
    relevance_score: post.relevance_score
  }
}));

const wpPost = $json;
const taskData = $items('IF Has Related Posts')[$itemIndex]?.json || {};

const currentContent = wpPost.content?.rendered || '';
const newPost = taskData.new_post;

if (currentContent.includes(newPost.url) || currentContent.includes(newPost.slug)) {
  return [{ json: { skip: true, reason: 'Already linked', target_wp_id: taskData.target_wp_post_id } }];
}

return [{ json: { target_wp_post_id: taskData.target_wp_post_id, target_title: taskData.target_title, new_post: newPost, current_content: currentContent } }];

const data = $json;

const systemPrompt = `You are an internal linking specialist. Insert ONE link to a new article into existing content.

RULES:
1. Find ONE natural place for the link.
2. Anchor text: 2-5 words, contextually relevant.
3. NO links in first paragraph or headings.
4. Add link mid-paragraph where context relates.
5. DO NOT change other content.
6. If no natural place, set link_added: false.

Output JSON:
{ "modified_content": "<HTML with link>", "link_added": true/false, "anchor_text": "text" or null }`;

const userPrompt = `Insert link to NEW article into existing article.

NEW ARTICLE:
- Title: "${data.new_post.title}"
- URL: ${data.new_post.url}
- Topic: ${data.new_post.primary_keyword || data.new_post.category}

EXISTING ARTICLE: "${data.target_title}"

EXISTING HTML:
${data.current_content}

Find ONE natural place. Output JSON only.`;

return [{ json: { ...data, ai_system_prompt: systemPrompt, ai_user_prompt: userPrompt } }];

const sourceData = $items('Build Bidirectional AI Prompt')[$itemIndex]?.json || {};
const aiResponse = $json;

function extractJson(text) {
  const cleaned = String(text || '').replace(/^```json\s*/i, '').replace(/```$/i, '').trim();
  const first = cleaned.indexOf('{');
  const last = cleaned.lastIndexOf('}');
  if (first === -1 || last === -1) throw new Error('No JSON');
  return JSON.parse(cleaned.slice(first, last + 1));
}

try {
  const result = extractJson(aiResponse.choices?.[0]?.message?.content || '');
  if (!result.link_added) return [{ json: { skip: true, reason: 'No natural place found' } }];
  return [{ json: { target_wp_post_id: sourceData.target_wp_post_id, target_title: sourceData.target_title, new_post_title: sourceData.new_post.title, new_post_url: sourceData.new_post.url, modified_content: result.modified_content, anchor_text: result.anchor_text } }];
} catch (e) {
  return [{ json: { skip: true, reason: 'AI error: ' + e.message } }];
}

